(function () {
  function addStyle() { if (document.getElementById('gfe-style')) return; var s = document.createElement('style'); s.id = 'gfe-style'; s.textContent = '.gfe-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.gfe-row{display:flex;gap:10px;flex-wrap:wrap;align-items:end}.gfe-row label{flex:1;min-width:220px;display:flex;flex-direction:column;gap:5px}.gfe-row input{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.gfe-out{margin-top:12px;padding:12px;border-radius:8px;background:#f8f9fa;line-height:1.7}.gfe-table{width:100%;border-collapse:collapse;margin-top:10px}.gfe-table th,.gfe-table td{border:1px solid #e5e7eb;padding:7px;text-align:left}.gfe-hit{padding:10px;border-left:4px solid #28a745;background:#d4edda;border-radius:8px}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.gfeMounted) return; host.dataset.gfeMounted = '1'; addStyle(); host.innerHTML = '<div class="gfe-wrap"><h4>📚 Khám phá hàm sinh</h4><div class="gfe-row"><label>Dãy a0,a1,... <input data-seq value="1,1,1,1,1,1"></label><button type="button" data-run>Tính hàm sinh</button></div><div class="gfe-out"></div></div>'; var out = host.querySelector('.gfe-out'); function term(a, i) { if (i === 0) return String(a); return a + '·x' + (i > 1 ? '<sup>' + i + '</sup>' : ''); } function run() { var arr = host.querySelector('[data-seq]').value.split(',').map(function (x) { return parseFloat(x.trim()); }).filter(function (x) { return !isNaN(x); }).slice(0, 10), first = arr.slice(0, 6), hit = 'Chưa nhận ra mẫu đóng đơn giản.'; if (arr.length && arr.every(function (x) { return x === arr[0]; })) hit = 'Dãy hằng ' + arr[0] + ': G(x) = ' + arr[0] + '/(1-x).'; else if (arr.every(function (x, i) { return x === i; })) hit = 'Dãy 0,1,2,3,...: G(x) = x/(1-x)².'; else if (arr.every(function (x, i) { return x === i + 1; })) hit = 'Dãy 1,2,3,4,...: G(x) = 1/(1-x)².'; else if (arr.every(function (x, i) { return x === Math.pow(2, i); })) hit = 'Dãy 1,2,4,8,...: G(x) = 1/(1-2x).'; out.innerHTML = '<p><strong>G(x)</strong> = ' + first.map(term).join(' + ') + ' + ...</p><div class="gfe-hit">' + hit + '</div><table class="gfe-table"><tr><th>Dãy</th><th>Hàm sinh</th></tr><tr><td>1,1,1,...</td><td>1/(1-x)</td></tr><tr><td>0,1,2,3,...</td><td>x/(1-x)²</td></tr><tr><td>1,2,3,4,...</td><td>1/(1-x)²</td></tr><tr><td>1,b,b²,...</td><td>1/(1-bx)</td></tr><tr><td>C(n,k)</td><td>(1+x)^n</td></tr></table>'; } host.querySelector('[data-run]').addEventListener('click', run); run(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="generating-function-explorer"]').forEach(mount); });
}());
